{"error": {"code": "VALIDATION_ERROR", "message": "Email is required", "field": "email"}}

Never expose stack traces or internal details. Log full errors server-side. Include a request ID for debugging. Rate limit error responses to prevent information leakage.

def validate_config(config: dict) -> list[str]:
    """Validate a configuration dictionary. Returns a list of error messages."""
    errors = []
    if 'port' not in config:
        errors.append('Missing required field: port')
    elif not isinstance(config['port'], int) or not (1 <= config['port'] <= 65535):
        errors.append(f'Port must be 1-65535, got {config["port"]}')
    if 'host' in config and not isinstance(config['host'], str):
        errors.append(f'Host must be a string, got {type(config["host"]).__name__}')
    if 'timeout' in config and config['timeout'] < 0:
        errors.append(f'Timeout must be non-negative, got {config["timeout"]}')
    return errors

